#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[100005]; scanf("%s", s);
        int cnt0=0;
        for(int i=0;i<N;i++) if(s[i]=='0') cnt0++;
        for(int i=0;i<cnt0;i++) putchar('0');
        for(int i=cnt0;i<N;i++) putchar('1');
        putchar('\n');
    }
    return 0;
}

