const T = Number(input[idx++]);
let output = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const s = input[idx++];
  let cnt0 = 0;
  for (let i = 0; i < s.length; i++) if (s[i] === '0') cnt0++;
  output.push('0'.repeat(cnt0) + '1'.repeat(N - cnt0));
}
console.log(output.join('\n'));

